import{_ as t,o as a,c as s,aa as i}from"./chunks/framework.vXJbu8_U.js";const f=JSON.parse('{"title":"Core concepts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md","lastUpdated":1781017118000}'),r={name:"guide/concepts.md"};function c(o,e,d,n,l,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="core-concepts" tabindex="-1">Core concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core concepts&quot;">​</a></h1><h2 id="effect-first" tabindex="-1">Effect-first <a class="header-anchor" href="#effect-first" aria-label="Permalink to &quot;Effect-first&quot;">​</a></h2><p>A query wraps your <strong>real effector <code>Effect</code></strong>. It is not a black box with an internal executor — your effect is a first-class unit: visible in devtools, composable with <code>attach</code>, and fork-friendly for SSR and tests.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> query</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createQuery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ effect: myFx });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">query.__.effect </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> myFx; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// the real effect</span></span></code></pre></div><h2 id="lifecycle-status" tabindex="-1">Lifecycle &amp; status <a class="header-anchor" href="#lifecycle-status" aria-label="Permalink to &quot;Lifecycle &amp; status&quot;">​</a></h2><p><code>$status</code> moves through <code>&#39;initial&#39; → &#39;pending&#39; → &#39;done&#39; | &#39;fail&#39;</code>. A query exposes:</p><table tabindex="0"><thead><tr><th>store/event</th><th>meaning</th></tr></thead><tbody><tr><td><code>$data</code></td><td>latest (validated, mapped) result</td></tr><tr><td><code>$error</code></td><td>latest error</td></tr><tr><td><code>$status</code></td><td><code>initial | pending | done | fail</code></td></tr><tr><td><code>$pending</code></td><td>request (or retry) in flight</td></tr><tr><td><code>$stale</code></td><td>current data is past <code>staleAfter</code></td></tr><tr><td><code>$params</code></td><td>last params the query ran with</td></tr><tr><td><code>finished.{done,fail,finally}</code></td><td>lifecycle events</td></tr><tr><td><code>aborted</code></td><td>a result was discarded (concurrency / cancel / skip)</td></tr></tbody></table><h2 id="triggers" tabindex="-1">Triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to &quot;Triggers&quot;">​</a></h2><ul><li><code>start(params)</code> — run, honoring cache / concurrency / enabled.</li><li><code>refresh(params)</code> / <code>refetch(params)</code> — run, bypassing cache freshness.</li><li><code>reset()</code> — back to initial, abort in-flight.</li><li><code>cancel()</code> — abort in-flight, keep data.</li></ul><h2 id="the-engine" tabindex="-1">The engine <a class="header-anchor" href="#the-engine" aria-label="Permalink to &quot;The engine&quot;">​</a></h2><p>Internally the query is a graph of plain effector units (<code>createStore</code> / <code>createEvent</code> / <code>sample</code>). All machinery (concurrency, retry, cache) lives in the engine and is configured by <strong>operators</strong>; the inline <code>createQuery</code> options are sugar over them. Config values can be constants or reactive <code>Store</code>s — see <a href="/effector-query/api/queries#sourced-reactive-config">sourced config</a>.</p><h2 id="ssr-tests" tabindex="-1">SSR &amp; tests <a class="header-anchor" href="#ssr-tests" aria-label="Permalink to &quot;SSR &amp; tests&quot;">​</a></h2><p>Because it&#39;s plain effector, <code>fork()</code> + <code>allSettled()</code> work as usual — no special test utilities. See <a href="/effector-query/recipes/ssr-and-testing">SSR &amp; testing</a>.</p>`,13)])])}const u=t(r,[["render",c]]);export{f as __pageData,u as default};
